+        assert_eq!(
+            classify_webgpu_surface_error(&wgpu::SurfaceError::Lost),
+            WebGpuSurfaceErrorAction::Retry
+        );
+        assert_eq!(
+            classify_webgpu_surface_error(&wgpu::SurfaceError::Outdated),
+            WebGpuSurfaceErrorAction::Retry
+        );
