+
+    #[test]
+    fn webgpu_surface_error_classification_skips_timeout_frames() {
+        assert_eq!(
+            classify_webgpu_surface_error(&wgpu::SurfaceError::Timeout),
+            WebGpuSurfaceErrorAction::SkipFrame
+        );
+    }
+
+    #[test]
